import heapq
from collections import defaultdict, deque, Counter


class CycleError(Exception):
    pass


class NotConnectedError(Exception):
    pass


def deep_search(x):
    return x.pop()


def breadth_search(x):
    return x.popleft()


def contains_edge(graph, edge):
    node_a, node_b = edge
    return node_a in graph[node_b] and node_b in graph[node_a]


def contains_arc(graph, arc):
    return arc[1] in graph[arc[0]]


def remove_edge(graph, edge):
    """
    >>> graph = {0: {1}, 1: {0}}
    >>> remove_edge(graph, frozenset([0, 1]))
    >>> graph
    {0: set(), 1: set()}
    """
    node_a, node_b = edge
    graph[node_a].remove(node_b)
    graph[node_b].remove(node_a)


def remove_arc(graph, arc):
    graph[arc[0]].remove(arc[1])


def convert(graph, mapping):
    return {
        mapping(node): {mapping(neighbor) for neighbor in neighbors}
        for node, neighbors in graph.items()
    }


def merge_disjoint(graphs):
    """
    >>> merge_disjoint([])
    {}
    >>> merge_disjoint([{0: {1}, 1: set()}, {2: set()}])
    {0: {1}, 1: set(), 2: set()}
    """
    return {node: neighbors for graph in graphs for node, neighbors in graph.items()}


def merge(graphs):
    """
    >>> merge([])
    {}
    >>> merge([{0: {1}, 1: {0}}, {1: {2}, 2: set()}])
    {0: {1}, 1: {0, 2}, 2: set()}
    """
    merged = defaultdict(set)
    for graph in graphs:
        for node, neighbors in graph.items():
            merged[node].update(neighbors)
    return dict(merged)


def convert_to_identifiers(graph):
    """
    >>> convert_to_identifiers({})
    {}
    >>> convert_to_identifiers({"a": set()})
    {0: set()}
    >>> convert_to_identifiers({"a": {"b"}, "b": set()})
    {0: {1}, 1: set()}
    """
    mapping = {node: i for i, node in enumerate(graph)}
    return convert(graph, lambda x: mapping[x])


def merge_identifiers(graphs):
    """
    >>> merge_identifiers([])
    {}
    >>> merge_identifiers([{0: {1}, 1: {0}}, {0: {1}, 1: set()}])
    {0: {1}, 1: {0}, 2: {3}, 3: set()}
    """
    offset = 0
    converted = []
    for identifiers in graphs:
        converted.append(convert(identifiers, lambda x: x + offset))
        offset += len(identifiers)
    return merge_disjoint(converted)


def to_indices(graph):
    """
    >>> to_indices({})
    []
    >>> to_indices({0: set()})
    [set()]
    >>> to_indices({0: {1}, 1: set()})
    [{1}, set()]
    """
    mapping = {node: index for index, node in enumerate(graph)}
    return [
        {mapping[neighbor] for neighbor in neighbors}
        for node, neighbors in graph.items()
    ]


def from_indices(indices, node_list):
    return {
        node_list[i]: {node_list[j] for j in neighbors}
        for i, neighbors in enumerate(indices)
    }


def from_edges(edges):
    """
    >>> from_edges(set())
    {}
    >>> from_edges({frozenset([0, 1])})
    {0: {1}, 1: {0}}
    """
    graph = defaultdict(set)
    for node_a, node_b in edges:
        graph[node_a].add(node_b)
        graph[node_b].add(node_a)
    return dict(graph)


def to_edges(graph):
    """
    >>> to_edges({})
    set()
    >>> to_edges({0: set()})
    set()
    >>> to_edges({0: {1}, 1: set()})
    {frozenset({0, 1})}
    >>> to_edges({0: {1}, 1: {0}})
    {frozenset({0, 1})}
    """
    return {
        frozenset([vertexA, vertexB])
        for vertexA, neighbors in graph.items()
        for vertexB in neighbors
    }


def get_default_weight(node_a, node_b):
    return 0.0 if node_a == node_b else 1.0


def search(graph, start_node=None, search_method=None):
    """Browse topologically through the graph
    If "startNode" is not defined, an arbitrary node is chosen as a start
    "search_method" is either "deep_search" or "breadth_search"
    """
    search_method = search_method or deep_search
    if not graph:
        return

    if start_node is None:
        try:
            node = next(iter(graph))
        except StopIteration:
            return
    else:
        node = start_node
    nodes_to_process = deque()
    nodes_discovered = defaultdict(lambda: False)
    nodes_to_process.append(node)
    nodes_discovered[node] = True
    while nodes_to_process:
        node = search_method(nodes_to_process)
        neighbors = [
            neighbor for neighbor in graph[node] if not nodes_discovered[neighbor]
        ]
        nodes_to_process += neighbors
        for neighbor in neighbors:
            nodes_discovered[neighbor] = True
        yield node


def is_valid(graph):
    """
    >>> is_valid({0: {}})
    True
    >>> is_valid({0: {1}})
    False
    """
    return all(
        neighbor in graph for neighbors in graph.values() for neighbor in neighbors
    )


def dijkstra(graph, seeds, distance_getter=get_default_weight):
    """Find the shortest paths to "seeds", using a dijkstra algorithm.
    Return a dictionary which contains the distance to the closest seed for each node and
    a dictionary which contains the neighbor which leads to the closest seed for each node

    >>> dijkstra({}, {})
    ({}, {})
    >>> dijkstra({0: {1}, 1: set()}, {0: 0.})
    ({0: 0.0, 1: inf}, {0: None, 1: None})
    >>> dijkstra({0: {1}, 1: set()}, {1: 0.})
    ({0: 1.0, 1: 0.0}, {0: 1, 1: None})
    >>> dijkstra({0: {1}, 1: set()}, {})
    ({0: inf, 1: inf}, {0: None, 1: None})
    """
    followers = {node: None for node in graph}
    couples_to_process = [(distance, seed) for seed, distance in seeds.items()]
    nodes_discovered = {node: False for node in graph}
    distances = {node: seeds.get(node, float("inf")) for node in graph}
    inverse = reverse(graph)
    while couples_to_process:
        min_distance, min_node = heapq.heappop(couples_to_process)
        if not nodes_discovered[min_node]:
            nodes_discovered[min_node] = True
            for neighbor in inverse[min_node]:
                if not nodes_discovered[neighbor]:
                    distance = distance_getter(min_node, neighbor)
                    new_distance = min_distance + distance
                    if new_distance < distances[neighbor]:
                        distances[neighbor] = new_distance
                        heapq.heappush(couples_to_process, (new_distance, neighbor))
                        followers[neighbor] = min_node
    return distances, followers


def shortest_paths(graph, destinations, distance_getter=get_default_weight):
    return dijkstra(
        graph,
        {destination: 0.0 for destination in destinations},
        distance_getter=distance_getter,
    )


def shortest_path(graph, destination, distance_getter=get_default_weight):
    return shortest_paths(graph, {destination}, distance_getter=distance_getter)


def pick(determinist):
    if len(determinist) > 1:
        raise RuntimeError(
            "Picking an element from {} is ambiguous".format(determinist)
        )
    return next(iter(determinist)) if determinist else None


def from_followeres(followers):
    return {
        node: set() if following is None else {following}
        for node, following in followers.items()
    }


def to_followers(graph):
    return {node: pick(neighbors) for node, neighbors in graph.items()}


def reverse(graph):
    """Return an identical graph if the graph is non-oriented

    >>> reverse({})
    {}
    >>> reverse({0: set()})
    {0: set()}
    >>> reverse({0: {1}, 1: set(), 2: set()})
    {0: set(), 1: {0}, 2: set()}
    """
    inverse = {node: set() for node in graph}
    for node, neighbors in graph.items():
        for neighbor in neighbors:
            inverse[neighbor].add(node)
    return inverse


def find_starts(graph):
    """Return an empty set if the graph is non-oriented

    >>> find_starts({})
    set()
    >>> find_starts({0: set()})
    {0}
    >>> find_starts({0: {1}, 1: set(), 2: set()})
    {0, 2}
    """
    return find_ends(reverse(graph))


def find_ends(graph):
    """Return an empty set if the graph is non-oriented

    >>> find_ends({})
    set()
    >>> find_ends({0: set()})
    {0}
    >>> find_ends({0: {1}, 1: set(), 2: set()})
    {1, 2}
    """
    return {node for node, neighbors in graph.items() if not neighbors}


def to_hierarchy(graph):
    """The graph must be acyclic and oriented

    >>> to_hierarchy({})
    {}
    >>> to_hierarchy({0: set()})
    {0: {}}
    >>> to_hierarchy({0: {1}, 1: set()})
    {0: {1: {}}}
    >>> to_hierarchy({0: {1, 2}, 1: set(), 2: set()})
    {0: {1: {}, 2: {}}}
    """
    starts = find_starts(graph)
    if graph and not starts:
        raise CycleError()
    root = {start: {} for start in starts}
    visited = set()
    hierarchies = [root]
    while hierarchies:
        hierarchy = hierarchies.pop()
        for node in hierarchy:
            if node in visited:
                raise CycleError(node)
            visited.add(node)
            children = {child: {} for child in graph[node]}
            hierarchy[node] = children
            hierarchies.append(children)
    return root


def unorient_graph(graph):
    unoriented = {node: set() for node in graph}
    for tail, neighbors in graph.items():
        for head in neighbors:
            unoriented[tail].add(head)
            unoriented[head].add(tail)
    return unoriented


def from_path(path):
    """
    >>> from_path([])
    {}
    >>> from_path([0])
    {0: set()}
    >>> from_path([0, 1, 2])
    {0: {1}, 1: {2}, 2: set()}
    """
    graph = {
        node: {path[i]} if i < len(path) else set() for i, node in enumerate(path, 1)
    }
    if len(graph) != len(path):
        raise CycleError({node for node, count in Counter(path).items() if count > 1})
    return graph


def to_path(graph):
    """
    >>> to_path({})
    []
    >>> to_path({0: set()})
    [0]
    >>> to_path({0: {1}, 1: {2}, 2: set()})
    [0, 1, 2]
    """
    if not graph:
        return []
    start = pick(find_starts(graph))
    if start is None:
        raise CycleError()
    path = unroll_path(start, to_followers(graph))
    if len(path) != len(graph):
        raise NotConnectedError()
    return path


def from_arcs(arcs):
    graph = defaultdict(set)
    for tail, head in arcs:
        graph[tail].add(head)
    return dict(graph)


def to_arcs(graph):
    return {(tail, head) for tail, neighbors in graph.items() for head in neighbors}


def border(graph, interior):
    """
    >>> border({}, {})
    set()
    >>> border({0: set()}, {})
    set()
    >>> border({0: {1}, 1: {0}}, {0})
    {0}
    >>> border({0: {1}, 1: {0, 2}, 2: {1}}, {0, 1})
    {1}
    """
    return {
        node
        for node in interior
        for neighbor in graph[node]
        if neighbor not in interior
    }


def boundary(graph, interior):
    """
    >>> boundary({}, {})
    set()
    >>> boundary({0: set()}, {})
    set()
    >>> boundary({0: {1}, 1: {0}}, {0})
    {1}
    >>> boundary({0: {1}, 1: {0, 2}, 2: {1}}, {0, 1})
    {2}
    """
    return {
        neighbor
        for node in interior
        for neighbor in graph[node]
        if neighbor not in interior
    }


def extract(graph, nodes):
    return {
        node: {neighbor for neighbor in graph[node] if neighbor in nodes}
        for node in nodes
    }


def intersection(graph, nodes):
    """
    >>> intersection({}, set())
    {}
    >>> intersection({0: {1}, 1: {0}}, set())
    {}
    >>> intersection({0: {1}, 1: {0}}, {0})
    {0: set()}
    """
    return extract(graph, graph.keys() & nodes)


def difference(graph, nodes):
    """
    >>> difference({}, set())
    {}
    >>> difference({0: {1}, 1: {0}}, set())
    {0: {1}, 1: {0}}
    >>> difference({0: {1}, 1: {0}}, {0})
    {1: set()}
    """
    return extract(graph, graph.keys() - nodes)


def unroll_path(start, followers):
    """
    >>> unroll_path(0, {0: None})
    [0]
    >>> unroll_path(0, {0: 1, 1: 2, 2: None})
    [0, 1, 2]
    """
    node = start
    path = []
    visited = set()
    while node is not None:
        if node in visited:
            raise CycleError(node)
        visited.add(node)
        path.append(node)
        node = followers[node]
    return path


def compute_path_in_followers(followers, start, end):
    path = unroll_path(start, followers)
    if path[-1] != end:
        raise NotConnectedError(start, end)
    return path


def compute_path(graph, start, end, distance_getter=get_default_weight):
    """
    >>> compute_path({0: set()}, 0, 0)
    [0]
    >>> compute_path({0: {1}, 1: set()}, 0, 1)
    [0, 1]
    >>> compute_path({0: {1}, 1: {0}}, 0, 1)
    [0, 1]
    """
    _, followers = shortest_path(graph, end, distance_getter)
    return compute_path_in_followers(followers, start, end)


def find_connected_components(graph):
    """'graph' must be non-oriented

    >>> find_connected_components({})
    []
    >>> find_connected_components({0: set()})
    [{0}]
    >>> find_connected_components({0: {1}, 1: {0}, 2: {3}, 3: {2}})
    [{0, 1}, {2, 3}]
    >>> find_connected_components({0: {2}, 1: {2}, 2: {0, 1}})
    [{0, 1, 2}]
    """
    non_visited = set(graph.keys())
    labels = {}
    result = []
    queue = deque()
    last_label = 0
    while non_visited:
        current = non_visited.pop()
        labels[current] = last_label
        result.append({current})
        last_label += 1
        queue.appendleft(current)
        while queue:
            current = queue.pop()
            label = labels[current]
            neighbors = graph[current]
            for neighbor in neighbors:
                if neighbor in non_visited:
                    queue.appendleft(neighbor)
                    if neighbor not in labels:
                        labels[neighbor] = labels[current]
                    result[label].add(neighbor)
                    non_visited.remove(neighbor)
    return result


def find_all(graph, comparator):
    """
    >>> find_all({}, lambda node, neighbor: node == neighbor)
    set()
    >>> find_all({0: {0}}, lambda node, neighbor: node == neighbor)
    {0}
    >>> find_all({0: {1}, 1: set()}, lambda node, neighbor: node == neighbor)
    {1}
    """
    return {
        node
        for node, neighbors in graph.items()
        if all(comparator(node, neighbor) for neighbor in neighbors)
    }
